import { useWindowWidth } from "../hooks/useWindowWidth";
import SiteFooter from "../components/SiteFooter";

// ─── About Page ───────────────────────────────────────────────────────────────
// Figma: MacBook Pro 14" - 35 (1512×3860)

export default function AboutPage() {
  return (
    <div style={{ width: "100%" }}>
      <HeroSection />
      <TealSection />
      {/* Figma: 78px cream gap between TealSection (ends y=2962) and TwoColumnSection group (starts y=3040) */}
      <div
        style={{
          width: "100%",
          height: "clamp(50px, 5.16vw, 78px)",
          backgroundColor: "rgb(252,248,235)",
        }}
      />
      <TwoColumnSection />
      {/* Figma: 78px cream gap between TwoColumnSection (ends y=3680) and QuoteSection (starts y=3758) */}
      <div
        style={{
          width: "100%",
          height: "clamp(50px, 5.16vw, 78px)",
          backgroundColor: "rgb(252,248,235)",
        }}
      />
      <QuoteSection />
      <ValuesSection />
      <SiteFooter />
    </div>
  );
}

// ─── Hero ─────────────────────────────────────────────────────────────────────
function HeroSection() {
  return (
    <section
      style={{
        width: "100%",
        height: "calc(100dvh - 60px)",
        marginTop: "60px",
        overflow: "hidden",
        lineHeight: 0,
      }}
    >
      <img
        src="/assets/about/hero-image.png"
        alt="About NH48"
        style={{
          width: "100%",
          height: "100%",
          objectFit: "cover",
          objectPosition: "center",
          display: "block",
        }}
      />
    </section>
  );
}

// ─── Bottom arch border ────────────────────────────────────────────────────────
// Figma: alternating long (112×72) + short (112×45), color rgb(15,59,55)
function MotifBorder({ right, left }) {
  return (
    <div
      aria-hidden="true"
      style={{
        width: "100%",
        height: "72px",
        display: "flex",
        alignItems: "flex-end",
        overflow: "hidden",
      }}
    >
      {Array.from({ length: 12 }, (_, i) => [
        <img
          key={`t${i}`}
          src={right}
          style={{
            width: "112px",
            height: "72px",
            flexShrink: 0,
            alignSelf: "flex-start",
            display: "block",
          }}
        />,
        <img
          key={`s${i}`}
          src={left}
          style={{
            width: "112px",
            height: "45px",
            flexShrink: 0,
            display: "block",
          }}
        />,
      ]).flat()}
    </div>
  );
}

// ─── Teal section ─────────────────────────────────────────────────────────────
// Figma: bg=rgb(20,83,77) h=479px
// Heading: BERNIER 64px rgb(242,212,62) at left=18.5% top=10%
// Body:    Helvetica Neue 32px w500 rgba(255,255,255,0.63) at left=23.5% top=49%
function TealSection() {
  const width = useWindowWidth();
  const mob = width < 768;

  const bodyStyle = {
    fontFamily: "'Helvetica Neue', Helvetica, Arial, sans-serif",
    fontWeight: 500,
    color: "rgba(255,255,255,0.63)",
    lineHeight: 1.22,
    textTransform: "uppercase",
    letterSpacing: "-1.92px",
    textAlign: "center",
    margin: 0,
  };

  if (mob) {
    return (
      <section
        style={{
          width: "100%",
          backgroundColor: "rgb(20,83,77)",
          padding: "48px 24px 0",
        }}
      >
        <h2
          style={{
            fontFamily: "'BERNIER Distressed', cursive",
            fontSize: "clamp(28px, 7vw, 48px)",
            color: "rgb(242,212,62)",
            lineHeight: 1.15,
            margin: "0 0 24px",
          }}
        >
          Where two cities meet on a single plate
        </h2>
        <p
          style={{
            ...bodyStyle,
            fontSize: "clamp(16px, 4vw, 22px)",
            marginBottom: "40px",
          }}
        >
          A road, a reunion, and a shared dream — NH48 is where the flavors of
          Delhi and Mumbai find each other.
        </p>
        <MotifBorder right = "/assets/about/section-2-motif-long.png" left = "/assets/about/section-2-motif-short.png" />
      </section>
    );
  }

  return (
    <section
      style={{
        position: "relative",
        width: "100%",
        backgroundColor: "rgb(20,83,77)",
        height: "clamp(360px, 31.7vw, 479px)",
        overflow: "hidden",
      }}
    >
      {/* Heading — centered horizontally, pushed down from top */}
      <h2
        style={{
          position: "absolute",
          left: "10%",
          top: "22%",
          width: "80%",
          fontFamily: "'BERNIER Distressed', cursive",
          fontSize: "clamp(28px, 3.44vw, 52px)",
          color: "rgb(242,212,62)",
          lineHeight: 1.15,
          textAlign: "center",
          margin: 0,
        }}
      >
        Where two cities meet on a single plate
      </h2>

      {/* Body — centered, proportionally below heading */}
      <p
        style={{
          ...bodyStyle,
          position: "absolute",
          left: "23.5%",
          top: "50%",
          width: "53.1%",
          fontSize: "clamp(16px, 2.12vw, 32px)",
        }}
      >
        A road, a reunion, and a shared dream — NH48 is where the flavors of
        Delhi and Mumbai find each other.
      </p>

      {/* Bottom border */}
      <div style={{ position: "absolute", bottom: 0, left: 0, right: 0 }}>
        <MotifBorder right="/assets/about/section-2-motif-long.png" left="/assets/about/section-2-motif-short.png" />
      </div>
    </section>
  );
}

